import time

class LatencyTracker:
    def __init__(self):
        self.t_vad_end: float = 0       # when VAD fired end-of-turn
        self.t_asr_final: float = 0     # when final transcript arrived
        self.t_llm_ttft: float = 0      # when LLM emitted first token
        self.t_tts_first_audio: float = 0  # when TTS emitted first PCM chunk

    def on_vad_end(self):
        self.t_vad_end = time.perf_counter()

    def on_asr_final(self):
        self.t_asr_final = time.perf_counter()

    def on_llm_first_token(self):
        self.t_llm_ttft = time.perf_counter()

    def on_tts_first_audio(self):
        self.t_tts_first_audio = time.perf_counter()
        self.report()

    def report(self):
        print(f"[Latency] "
              f"VAD→ASR: {(self.t_asr_final - self.t_vad_end)*1000:.0f}ms  "
              f"ASR→LLM-TTFT: {(self.t_llm_ttft - self.t_asr_final)*1000:.0f}ms  "
              f"LLM→TTS-1st: {(self.t_tts_first_audio - self.t_llm_ttft)*1000:.0f}ms  "
              f"TTFB: {(self.t_tts_first_audio - self.t_vad_end)*1000:.0f}ms")
